import (
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-gemini/db"
	"github.com/RICE-COMP318-FALL24/owldb-gemini/jsondata"
)

// ... PatchOp and PatchResult ...

type patchVisitor struct {
	op       PatchOp
	segments []string
}

func (v *patchVisitor) Map(m map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
	if len(v.segments) == 0 {
		if v.op.Op == "ObjectAdd" {
			// This shouldn't happen based on instructions "path up to, but not including, the last element refers to an object"
			// If segments is empty here, it means the path pointed exactly to this object.
			return jsondata.JSONValue{}, fmt.Errorf("invalid path for ObjectAdd")
		}
		return jsondata.JSONValue{}, fmt.Errorf("invalid path for %s", v.op.Op)
	}

	head := v.segments[0]
	if len(v.segments) == 1 && v.op.Op == "ObjectAdd" {
		// We are at the parent object of the property to add
		if _, exists := m[head]; !exists {
			m[head] = v.op.Value
		}
		return jsondata.NewJSONValue(m)
	}

	// Navigate deeper
	child, ok := m[head]
	if !ok {
		return jsondata.JSONValue{}, fmt.Errorf("path component not found: %s", head)
	}

	v.segments = v.segments[1:]
	newChild, err := jsondata.Accept(child, v)
	if err != nil {
		return jsondata.JSONValue{}, err
	}
	m[head] = newChild
	return jsondata.NewJSONValue(m)
}

func (v *patchVisitor) Slice(s []jsondata.JSONValue) (jsondata.JSONValue, error) {
	if len(v.segments) == 0 {
		// We are at the target array
		if v.op.Op == "ArrayAdd" {
			found := false
			for _, item := range s {
				if item.Equal(v.op.Value) {
					found = true
					break
				}
			}
			if !found {
				s = append(s, v.op.Value)
			}
			return jsondata.NewJSONValue(s)
		} else if v.op.Op == "ArrayRemove" {
			newS := make([]jsondata.JSONValue, 0, len(s))
			for _, item := range s {
				if !item.Equal(v.op.Value) {
					newS = append(newS, item)
				}
			}
			return jsondata.NewJSONValue(newS)
		}
		return jsondata.JSONValue{}, fmt.Errorf("invalid operation for array: %s", v.op.Op)
	}

	// Navigate deeper if the segment is an index?
	// The instructions don't explicitly say we can navigate into arrays with jsonpointer,
	// but jsonpointer definitely supports it (e.g., /a/0/b).
	// Let's assume we need to handle it.
	head := v.segments[0]
	var index int
	_, err := fmt.Sscanf(head, "%d", &index)
	if err != nil {
		return jsondata.JSONValue{}, fmt.Errorf("invalid array index: %s", head)
	}
	if index < 0 || index >= len(s) {
		return jsondata.JSONValue{}, fmt.Errorf("array index out of bounds: %d", index)
	}

	v.segments = v.segments[1:]
	newChild, err := jsondata.Accept(s[index], v)
	if err != nil {
		return jsondata.JSONValue{}, err
	}
	s[index] = newChild
	return jsondata.NewJSONValue(s)
}

func (v *patchVisitor) Bool(b bool) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into boolean")
}

func (v *patchVisitor) Float64(f float64) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into float64")
}

func (v *patchVisitor) String(s string) (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into string")
}

func (v *patchVisitor) Null() (jsondata.JSONValue, error) {
	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into null")
}

func applyPatch(data jsondata.JSONValue, op PatchOp) (jsondata.JSONValue, error) {
	ptr := op.Path
	if !strings.HasPrefix(ptr, "/") && ptr != "" {
		return jsondata.JSONValue{}, fmt.Errorf("invalid jsonpointer")
	}
	segments := strings.Split(strings.TrimPrefix(ptr, "/"), "/")
	if ptr == "" || ptr == "/" {
		segments = []string{}
	}
	// Special case for empty segments if ptr was just "/"
	if len(segments) == 1 && segments[0] == "" {
		segments = []string{}
	}

	// Unescape jsonpointer segments (~1 -> /, ~0 -> ~)
	for i, s := range segments {
		s = strings.ReplaceAll(s, "~1", "/")
		s = strings.ReplaceAll(s, "~0", "~")
		segments[i] = s
	}

	visitor := &patchVisitor{
		op:       op,
		segments: segments,
	}
	return jsondata.Accept(data, visitor)
}

