func (s *Server) handleDocument(w http.ResponseWriter, r *http.Request, pathInfo *db.PathInfo, username string) {
	switch r.Method {
	case http.MethodGet:
		doc, ok := s.resolveDocument(pathInfo)
		if !ok {
			s.errorResponse(w, http.StatusNotFound, "Document does not exist")
			return
		}

		if r.URL.Query().Get("mode") == "subscribe" {
			// Send current state first
			doc.Mu.RLock()
			s.notifyUpdate(r.URL.Path, doc)
			doc.Mu.RUnlock()

			s.sm.Subscribe(w, r, func(ev Event) bool {
				// Subscribe to a single document: only receive "update" and "delete" events for that particular document
				return ev.Path == r.URL.Path
			})
			return
		}

		doc.Mu.RLock()
		defer doc.Mu.RUnlock()
		jsonResponse(w, http.StatusOK, db.DocResponse{
			Path: r.URL.Path,
			Doc:  doc.Data,
			Meta: doc.Meta,
		})

	case http.MethodPut:
		s.handleDocumentPut(w, r, pathInfo, username)

	case http.MethodDelete:
		s.handleDocumentDelete(w, r, pathInfo, username)

	case http.MethodPatch:
		s.handleDocumentPatch(w, r, pathInfo, username)

	default:
		s.errorResponse(w, http.StatusMethodNotAllowed, "Method not allowed")
	}
}

