func (s *Server) handleCollectionQuery(w http.ResponseWriter, r *http.Request, pathInfo *db.PathInfo, username string) {
	index_any, ok := s.resolveCollection(pathInfo)
	if !ok {
		s.errorResponse(w, http.StatusNotFound, "Collection does not exist")
		return
	}
	index := index_any.(skiplist.DBIndex[string, *db.Document])

	interval := r.URL.Query().Get("interval")
	low, high := parseInterval(interval)

	if r.URL.Query().Get("mode") == "subscribe" {
		// Send initial states
		results, _ := index.Query(r.Context(), low, high)
		for _, pair := range results {
			doc := pair.Value
			doc.Mu.RLock()
			s.notifyUpdate(r.URL.Path + doc.Name, doc)
			doc.Mu.RUnlock()
		}

		s.sm.Subscribe(w, r, func(ev Event) bool {
			// Subscribe to a collection: receive events for all documents within the collection and delete events for the collection itself
			if ev.Path == r.URL.Path {
				return ev.Type == "delete"
			}
			if strings.HasPrefix(ev.Path, r.URL.Path) {
				docName := strings.TrimPrefix(ev.Path, r.URL.Path)
				if !strings.Contains(docName, "/") {
					// Check interval
					if (low == "" || docName >= low) && (high == "\xff" || docName <= high) {
						return true
